"use client";
import { useState, useEffect, memo, useRef } from 'react';
import dynamic from 'next/dynamic';
import { usePlayerStore } from '@/store/usePlayerStore';

// We cast the dynamic component to 'any' to stop the prop-type battlefield
const ReactPlayer = dynamic(() => import('react-player'), { 
  ssr: false,
  loading: () => <div className="hidden" /> 
}) as any;

const YouTubeIFrame = memo(() => {
  const { currentTrackId, isPlaying, volume, setProgress, setDuration, resetProgress } = usePlayerStore();
  const [isClient, setIsClient] = useState(false);
  const playerRef = useRef<any>(null);

  useEffect(() => {
    setIsClient(true);
  }, []);

  useEffect(() => {
    resetProgress(); // Reset progress when track changes
  }, [currentTrackId, resetProgress]);

  if (!isClient || !currentTrackId) return null;

  return (
    <div style={{ position: 'fixed', top: '-1000px', left: '-1000px', pointerEvents: 'none' }}>
      <ReactPlayer
        ref={playerRef}
        key={currentTrackId}
        url={`https://www.youtube.com/watch?v=${currentTrackId}`}
        playing={isPlaying}
        volume={volume}
        muted={false}
        width="1px"
        height="1px"
        onReady={(player: any) => {
          console.log("✅ YouTube Player Ready");
          playerRef.current = player;
          
          // Get duration when player is ready
          const internalPlayer = player.getInternalPlayer?.();
          if (internalPlayer) {
            const getDurationWithRetry = (attempts = 0) => {
              const duration = internalPlayer.getDuration();
              if (duration && duration > 0) {
                setDuration(duration);
                console.log("Duration set:", duration);
              } else if (attempts < 5) {
                setTimeout(() => getDurationWithRetry(attempts + 1), 300);
              }
            };
            setTimeout(() => getDurationWithRetry(), 100);
          }
        }}
        onProgress={(state: any) => {
          setProgress(state.playedSeconds);
        }}
        onPlay={() => {
          console.log("▶️ Video playing");
        }}
        onPause={() => {
          console.log("⏸️ Video paused");
        }}
        config={{
          youtube: {
            playerVars: { 
              autoplay: 1, 
              controls: 0, 
              modestbranding: 1,
              disablekb: 1,
              fs: 0,
              iv_load_policy: 3,
              origin: typeof window !== 'undefined' ? window.location.origin : '',
              playsinline: 1,
              rel: 0
            }
          }
        }}
      />
    </div>
  );
});

YouTubeIFrame.displayName = "YouTubeIFrame";
export default YouTubeIFrame;